const body = $input.first().json.body || {};

// Support both direct webhook calls and relay from events receiver
const rawText   = body.text || body.message || '';
const channelId = body.channel_id || body.channel || 'C0AJW9DTDSB';
const userId    = body.user_id || body.user || 'unknown';
const threadTs  = body.thread_ts || body.ts || '';
const userName  = body.user_name || body.username || 'unknown';

// Strip bot @mentions and leading/trailing whitespace
const stripped = rawText.replace(/<@[^>]+>/g, '').trim();

// ── Command-prefix override ─────────────────────────────────────────────────
// Allows forcing a classification type: /pm task|story|epic|bug|spike|initiative <text>
// e.g.  /pm bug Council not triggering
//       /pm spike Research LLM context caching
// If no prefix is present, forcedType is null → Ollama classifies.
const PREFIX_RE = /^(initiative|epic|story|task|bug|spike)\s+/i;
const prefixMatch = stripped.match(PREFIX_RE);

let forcedType = null;
let cleanText  = stripped;

if (prefixMatch) {
  forcedType = prefixMatch[1].toLowerCase();
  cleanText  = stripped.slice(prefixMatch[0].length).trim();
}

return [{ json: {
  text:       cleanText,
  rawText:    rawText,
  channelId,
  userId,
  userName,
  threadTs,
  forcedType   // null → classify with Ollama; string → skip LLM
}}];

// User explicitly typed the classification — no LLM needed.
const d = $input.first().json;

const DEFAULT_PRIORITY = { initiative: 2, epic: 2, story: 3, task: 3, bug: 2, spike: 3 };
const DEFAULT_ESTIMATE = { initiative: null, epic: 8, story: 5, task: 3, bug: 2, spike: 3 };

const classification = {
  type:        d.forcedType,
  title:       d.text.slice(0, 80),
  description: d.text,
  priority:    DEFAULT_PRIORITY[d.forcedType] || 3,
  labels:      [],
  estimate:    DEFAULT_ESTIMATE[d.forcedType] || null,
  reasoning:   `Manually forced to '${d.forcedType}' via command prefix.`
};

const PRIORITY_MAP = { urgent: 1, high: 2, medium: 3, low: 4 };

return [{ json: {
  ...d,
  classification,
  issueType:   classification.type,
  title:       classification.title,
  description: classification.description,
  priority:    classification.priority,
  labels:      classification.labels,
  estimate:    classification.estimate,
  reasoning:   classification.reasoning,
  shouldCreate: true
}}];

const raw    = $input.first().json.message?.content || '';
const parsed = $('Parse Input').first().json;

let classification;
try {
  // Extract JSON from response (handle markdown code blocks if Ollama wraps output)
  const jsonMatch = raw.match(/```(?:json)?\s*([\s\S]*?)\s*```/) ||
                    raw.match(/(\{[\s\S]*\})/);
  const jsonStr = jsonMatch ? jsonMatch[1] : raw;
  classification = JSON.parse(jsonStr.trim());
} catch(e) {
  classification = { type: 'ignore', reasoning: 'Could not parse Ollama response: ' + e.message };
}

// ── Spike guard: estimate must be ≤ 3 ────────────────────────────────────────
if (classification.type === 'spike' && classification.estimate > 3) {
  classification.estimate = 3;
}

// ── Priority string → Linear integer ─────────────────────────────────────────
const PRIORITY_MAP = { urgent: 1, high: 2, medium: 3, low: 4 };
const priorityInt = PRIORITY_MAP[classification.priority] || 3;

// ── Validate labels against allowed set ──────────────────────────────────────
const ALLOWED_LABELS = new Set(['automation','ai-core','infrastructure','monitoring','comfyui','research','devops']);
const labels = (classification.labels || []).filter(l => ALLOWED_LABELS.has(l));

return [{ json: {
  ...parsed,
  classification,
  issueType:   classification.type,
  title:       classification.title || parsed.text.slice(0, 80),
  description: classification.description || parsed.text,
  priority:    priorityInt,
  labels,
  estimate:    classification.estimate || null,
  reasoning:   classification.reasoning || '',
  shouldCreate: classification.type !== 'ignore'
}}];

