={{ (() => {
  const teams  = $('Get Linear Teams').first().json.data?.teams?.nodes || [];
  const teamId = teams[0]?.id || '';
  const d      = $('Merge Paths').first().json;

  const GITHUB_REPO = 'https://github.com/cschulz-ceo/ai-workers';

  // ── Type → Linear label prefix ────────────────────────────────────────────
  const TYPE_PREFIX = {
    initiative: '🌐 Initiative',
    epic:       '🗺️ Epic',
    story:      '📖 Story',
    task:       '✅ Task',
    bug:        '🐛 Bug',
    spike:      '🔬 Spike'
  };
  const typeLabel = TYPE_PREFIX[d.issueType] || '✅ Task';

  // ── Spike: add time-box note to description ───────────────────────────────
  const spikeNote = d.issueType === 'spike'
    ? '\n\n> ⏱️ **Spike** — time-boxed to ' + (d.estimate || 3) + ' pts. Deliverable: decision doc or ADR.'
    : '';

  const desc = d.description + spikeNote +
    '\n\n---\n' +
    '*Type:* ' + typeLabel + '\n' +
    '*Source:* Slack message from <@' + d.userId + '> in <#' + d.channelId + '>\n' +
    '*AI reasoning:* ' + d.reasoning + '\n' +
    '*Repository:* [cschulz-ceo/ai-workers](' + GITHUB_REPO + ')';

  const mutation = `
    mutation CreateIssue($input: IssueCreateInput!) {
      issueCreate(input: $input) {
        success
        issue {
          id
          identifier
          title
          url
          priority
          state { name }
        }
      }
    }
  `;

  const variables = {
    input: {
      teamId,
      title:       d.title,
      description: desc,
      priority:    d.priority,
      estimate:    d.estimate
    }
  };

  return JSON.stringify({ query: mutation, variables });
})() }}

