const issue = $input.first().json.data?.issueCreate?.issue;
const d     = $('Merge Paths').first().json;

if (!issue) {
  return [{ json: {
    channelId: d.channelId,
    threadTs:  d.threadTs,
    payload: JSON.stringify({
      channel:   d.channelId,
      thread_ts: d.threadTs || undefined,
      text: '⚠️ Linear issue creation failed. Check LINEAR_API_KEY env var.'
    })
  }}];
}

// ── Type → emoji + label ─────────────────────────────────────────────────────
const TYPE_META = {
  initiative: { emoji: '🌐', label: 'Initiative' },
  epic:       { emoji: '🗺️',  label: 'Epic'       },
  story:      { emoji: '📖', label: 'Story'      },
  task:       { emoji: '✅', label: 'Task'       },
  bug:        { emoji: '🐛', label: 'Bug'        },
  spike:      { emoji: '🔬', label: 'Spike'      }
};
const PRIORITY_META = {
  1: { emoji: '🔴', label: 'Urgent' },
  2: { emoji: '🟠', label: 'High'   },
  3: { emoji: '🟡', label: 'Medium' },
  4: { emoji: '🔵', label: 'Low'    }
};

const type     = TYPE_META[d.issueType]     || { emoji: '✅', label: 'Task'   };
const priority = PRIORITY_META[d.priority]  || { emoji: '🟡', label: 'Medium' };
const labelsStr = d.labels.length ? d.labels.map(l => '`' + l + '`').join('  ') : '_none_';
const estimateStr = d.estimate ? `${d.estimate} pts` : 'unestimated';
const forcedNote  = d.forcedType ? '  _(type forced via prefix)_' : '';
const spikeNote   = d.issueType === 'spike' ? '\n> ⏱️ Time-boxed spike — deliverable is a decision or ADR, not code.' : '';

const blocks = [
  {
    type: 'section',
    text: {
      type: 'mrkdwn',
      text:
        `${type.emoji} *<${issue.url}|${issue.identifier}: ${issue.title}>*  →  ${type.label} created in Linear${forcedNote}\n` +
        `├ ${priority.emoji} *${priority.label}*  •  📏 *${estimateStr}*  •  🏷️ ${labelsStr}\n` +
        `└ _${d.reasoning}_` +
        spikeNote
    }
  }
];

return [{ json: {
  channelId: d.channelId,
  threadTs:  d.threadTs,
  payload: JSON.stringify({
    channel:   d.channelId,
    thread_ts: d.threadTs || undefined,
    blocks
  })
}}];
